function solve(prices, strategy, k) {
    const n = prices.length;
    const prefix_original = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix_original[i + 1] = prefix_original[i] + strategy[i] * prices[i];
    }

    const prefix_prices = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix_prices[i + 1] = prefix_prices[i] + prices[i];
    }

    let original_profit = prefix_original[n];
    let max_delta = 0;
    const half = k / 2;

    for (let i = 0; i <= n - k; i++) {
        const original_sum = prefix_original[i + k] - prefix_original[i];
        const start = i + half;
        const end = i + k - 1;
        const sum_second = prefix_prices[end + 1] - prefix_prices[start];
        const delta = sum_second - original_sum;
        if (delta > max_delta) {
            max_delta = delta;
        }
    }

    return original_profit + Math.max(0, max_delta);
}

